import React, { useRef, useEffect } from 'react';

const VirtualKeyboard = ({ activeKey, isCorrect }) => {
  const lastKeyRef = useRef(null);
  const lastCorrectRef = useRef(null);

  const fingerMap = {
    'q': 'left-pinky', 'a': 'left-pinky', 'z': 'left-pinky', '1': 'left-pinky',
    'w': 'left-ring',  's': 'left-ring',  'x': 'left-ring',  '2': 'left-ring',
    'e': 'left-middle','d': 'left-middle','c': 'left-middle', '3': 'left-middle',
    'r': 'left-index', 'f': 'left-index', 'v': 'left-index', 't': 'left-index',
    'g': 'left-index', 'b': 'left-index', '4': 'left-index', '5': 'left-index',
    'y': 'right-index','h': 'right-index','n': 'right-index','u': 'right-index',
    'j': 'right-index','m': 'right-index','6': 'right-index','7': 'right-index',
    'i': 'right-middle','k': 'right-middle',',': 'right-middle','8': 'right-middle',
    'o': 'right-ring', 'l': 'right-ring', '.': 'right-ring', '9': 'right-ring',
    'p': 'right-pinky',';': 'right-pinky',"'": 'right-pinky','/': 'right-pinky',
    '0': 'right-pinky','-': 'right-pinky','=': 'right-pinky','[': 'right-pinky',
    ']': 'right-pinky',' ': 'thumbs'
  };

  const fingerNames = {
    'left-pinky':  'Left Pinky',
    'left-ring':   'Left Ring',
    'left-middle': 'Left Middle',
    'left-index':  'Left Index',
    'right-index': 'Right Index',
    'right-middle':'Right Middle',
    'right-ring':  'Right Ring',
    'right-pinky': 'Right Pinky',
    'thumbs':      'Both Thumbs'
  };

  const keyboardLayout = [
    ['1','2','3','4','5','6','7','8','9','0','-','='],
    ['q','w','e','r','t','y','u','i','o','p','[',']'],
    ['a','s','d','f','g','h','j','k','l',';',"'"],
    ['z','x','c','v','b','n','m',',','.','/'],
    ['SPACE']
  ];

  // Play sound immediately when isCorrect changes (synced to keystroke)
  useEffect(() => {
    if (isCorrect === null || isCorrect === undefined) return;
    // Only play if something actually changed
    if (lastKeyRef.current === activeKey && lastCorrectRef.current === isCorrect) return;
    lastKeyRef.current = activeKey;
    lastCorrectRef.current = isCorrect;
    if (isCorrect) playTick(); else playTock();
  }, [isCorrect, activeKey]);

  const playTick = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(900, ctx.currentTime);
      gain.gain.setValueAtTime(0.07, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.035);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.035);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  const playTock = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.setValueAtTime(280, ctx.currentTime);
      gain.gain.setValueAtTime(0.06, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.055);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.055);
      osc.onended = () => ctx.close();
    } catch (e) {}
  };

  const getFingerClass = (key) => fingerMap[key === 'SPACE' ? ' ' : key.toLowerCase()] || '';
  const currentFinger = activeKey ? (fingerMap[activeKey === ' ' ? ' ' : activeKey.toLowerCase()] || '') : '';
  const currentFingerName = fingerNames[currentFinger] || '';

  const isActive = (key) => {
    if (!activeKey) return false;
    if (key === 'SPACE') return activeKey === ' ';
    return key.toLowerCase() === activeKey.toLowerCase();
  };

  // Which finger div to highlight for left hand
  const leftFingerActive = (f) => currentFinger === `left-${f}` ? 'active' : '';
  const rightFingerActive = (f) => currentFinger === `right-${f}` ? 'active' : '';
  const thumbActive = currentFinger === 'thumbs' ? 'active' : '';

  return (
    <div className="virtual-keyboard">
      {/* Clean Finger Icon Hands */}
      <div className="hand-guidance">
        {/* Left Hand */}
        <div className="left-hand">
          <div className="hand-icon">
            <div className={`fi pinky ${leftFingerActive('pinky')}`} />
            <div className={`fi ring ${leftFingerActive('ring')}`} />
            <div className={`fi middle ${leftFingerActive('middle')}`} />
            <div className={`fi index ${leftFingerActive('index')}`} />
            <div className={`fi thumb ${thumbActive}`} />
          </div>
        </div>

        {/* Pill Instruction */}
        <div className="finger-instruction">
          {currentFingerName && (
            <div className="finger-name-box">
              <strong>{activeKey === ' ' ? 'SPACE' : activeKey?.toUpperCase()}</strong>
              <span className="pill-divider">|</span>
              <span>{currentFingerName}</span>
            </div>
          )}
        </div>

        {/* Right Hand */}
        <div className="right-hand">
          <div className="hand-icon">
            <div className={`fi thumb ${thumbActive}`} />
            <div className={`fi index ${rightFingerActive('index')}`} />
            <div className={`fi middle ${rightFingerActive('middle')}`} />
            <div className={`fi ring ${rightFingerActive('ring')}`} />
            <div className={`fi pinky ${rightFingerActive('pinky')}`} />
          </div>
        </div>
      </div>

      {/* Keyboard */}
      {keyboardLayout.map((row, ri) => (
        <div key={ri} className="keyboard-row">
          {row.map((key) => (
            <div
              key={key}
              className={`key${key === 'SPACE' ? ' space' : ''} ${getFingerClass(key)} ${isActive(key) ? 'active' : ''}`}
            >
              {key === 'SPACE' ? 'Space' : key}
            </div>
          ))}
        </div>
      ))}
      <div style={{ textAlign: 'center', marginTop: '0.4rem', color: '#9ca3af', fontSize: '0.72rem' }}>
        Home row: A S D F | J K L ;
      </div>
    </div>
  );
};

export default VirtualKeyboard;
